import{_ as p,e as a}from"./app.a229a4b5.js";const i={},e=a('<p>CDN\u8FD9\u4E2A\u6280\u672F\u5176\u5B9E\u8BF4\u8D77\u6765\u5E76\u4E0D\u590D\u6742\uFF0C\u6700\u521D\u7684\u6838\u5FC3\u7406\u5FF5\uFF0C\u5C31\u662F\u5C06\u5185\u5BB9\u7F13\u5B58\u5728\u7EC8\u7AEF\u7528\u6237\u9644\u8FD1\u3002</p><p><img src="https://pic2.zhimg.com/80/v2-5e53690a7bfaace4a5a61d1c2bfab609_720w.jpg" alt=""></p><h2 id="\u5185\u5BB9\u5206\u53D1\u6D41\u7A0B" tabindex="-1"><a class="header-anchor" href="#\u5185\u5BB9\u5206\u53D1\u6D41\u7A0B" aria-hidden="true">#</a> \u5185\u5BB9\u5206\u53D1\u6D41\u7A0B</h2><ol><li><p>\u5F53\u7528\u6237\u70B9\u51FBAPP\u4E0A\u7684\u5185\u5BB9\uFF0CAPP\u4F1A\u6839\u636EURL\u5730\u5740\u53BB\u672C\u5730DNS\uFF08\u57DF\u540D\u89E3\u6790\u7CFB\u7EDF\uFF09\u5BFB\u6C42IP\u5730\u5740\u89E3\u6790\u3002</p></li><li><p>\u672C\u5730DNS\u7CFB\u7EDF\u4F1A\u5C06\u57DF\u540D\u7684\u89E3\u6790\u6743\u4EA4\u7ED9CDN\u4E13\u7528DNS\u670D\u52A1\u5668\u3002</p></li><li><p>CDN\u4E13\u7528DNS\u670D\u52A1\u5668\uFF0C\u5C06CDN\u7684\u5168\u5C40\u8D1F\u8F7D\u5747\u8861\u8BBE\u5907IP\u5730\u5740\u8FD4\u56DE\u7528\u6237\u3002</p></li><li><p>\u7528\u6237\u5411CDN\u7684\u8D1F\u8F7D\u5747\u8861\u8BBE\u5907\u53D1\u8D77\u5185\u5BB9URL\u8BBF\u95EE\u8BF7\u6C42\u3002</p></li><li><p>CDN\u8D1F\u8F7D\u5747\u8861\u8BBE\u5907\u6839\u636E\u7528\u6237IP\u5730\u5740\uFF0C\u4EE5\u53CA\u7528\u6237\u8BF7\u6C42\u7684\u5185\u5BB9URL\uFF0C\u9009\u62E9\u4E00\u53F0\u7528\u6237\u6240\u5C5E\u533A\u57DF\u7684\u7F13\u5B58\u670D\u52A1\u5668\u3002</p></li><li><p>\u8D1F\u8F7D\u5747\u8861\u8BBE\u5907\u544A\u8BC9\u7528\u6237\u8FD9\u53F0\u7F13\u5B58\u670D\u52A1\u5668\u7684IP\u5730\u5740\uFF0C\u8BA9\u7528\u6237\u5411\u6240\u9009\u62E9\u7684\u7F13\u5B58\u670D\u52A1\u5668\u53D1\u8D77\u8BF7\u6C42\u3002</p></li><li><p>\u7528\u6237\u5411\u7F13\u5B58\u670D\u52A1\u5668\u53D1\u8D77\u8BF7\u6C42\uFF0C\u7F13\u5B58\u670D\u52A1\u5668\u54CD\u5E94\u7528\u6237\u8BF7\u6C42\uFF0C\u5C06\u7528\u6237\u6240\u9700\u5185\u5BB9\u4F20\u9001\u5230\u7528\u6237\u7EC8\u7AEF\u3002</p></li><li><p>\u5982\u679C\u8FD9\u53F0\u7F13\u5B58\u670D\u52A1\u5668\u4E0A\u5E76\u6CA1\u6709\u7528\u6237\u60F3\u8981\u7684\u5185\u5BB9\uFF0C\u90A3\u4E48\u8FD9\u53F0\u7F13\u5B58\u670D\u52A1\u5668\u5C31\u8981\u7F51\u7AD9\u7684\u6E90\u670D\u52A1\u5668\u8BF7\u6C42\u5185\u5BB9\u3002</p></li><li><p>\u6E90\u670D\u52A1\u5668\u8FD4\u56DE\u5185\u5BB9\u7ED9\u7F13\u5B58\u670D\u52A1\u5668\uFF0C\u7F13\u5B58\u670D\u52A1\u5668\u53D1\u7ED9\u7528\u6237\uFF0C\u5E76\u6839\u636E\u7528\u6237\u81EA\u5B9A\u4E49\u7684\u7F13\u5B58\u7B56\u7565\uFF0C\u5224\u65AD\u8981\u4E0D\u8981\u628A\u5185\u5BB9\u7F13\u5B58\u5230\u7F13\u5B58\u670D\u52A1\u5668\u4E0A\u3002</p></li></ol><h2 id="\u4F18\u52BF" tabindex="-1"><a class="header-anchor" href="#\u4F18\u52BF" aria-hidden="true">#</a> \u4F18\u52BF</h2><ul><li><p>\u52A0\u901F\u5185\u5BB9\u8BBF\u95EE\u3002</p></li><li><p>\u6E90\u670D\u52A1\u5668 IP \u88AB\u9690\u85CF\uFF0C\u53D7\u653B\u51FB\u7684\u6982\u7387\u5927\u5E45\u5EA6\u4E0B\u964D\u3002</p></li></ul><h2 id="cnd-\u4E0E\u901A\u4FE1\u884C\u4E1A" tabindex="-1"><a class="header-anchor" href="#cnd-\u4E0E\u901A\u4FE1\u884C\u4E1A" aria-hidden="true">#</a> CND \u4E0E\u901A\u4FE1\u884C\u4E1A</h2><p>\u4E92\u8054\u7F51\u670D\u52A1\u63D0\u4F9B\u5546\u91C7\u7528CDN\uFF0C\u662F\u4EE5\u5B58\u50A8\u6362\u65F6\u5EF6\u3002\u82B1\u94B1\u8D2D\u7F6ECDN\u670D\u52A1\u5668\u6216\u4E91\u8BA1\u7B97\u670D\u52A1\uFF0C\u4EE5\u6B64\u6362\u53D6\u66F4\u597D\u7684\u7528\u6237\u4F53\u9A8C\u3002</p><p>\u901A\u4FE1\u8FD0\u8425\u5546\u4E5F\u8FFD\u6367CDN\uFF0C\u4F46\u5B83\u4EEC\u7684\u76EE\u7684\uFF0C\u662F\u4EE5\u5B58\u50A8\u6362\u5E26\u5BBD\u2014\u2014\u901A\u8FC7<strong>\u670D\u52A1\u201C\u4E0B\u6C89\u201D</strong>\uFF0C\u51CF\u8F7B\u4E0A\u5C42\u9AA8\u5E72\u7F51\u7EDC\u7684\u6D41\u91CF\u538B\u529B\uFF0C\u907F\u514D\u786C\u4EF6\u6269\u5BB9\uFF0C\u964D\u4F4E\u7F51\u7EDC\u5EFA\u8BBE\u6210\u672C\u3002</p><hr><p>\u5F88\u591A\u8FD0\u8425\u5546\u5DF2\u7ECF\u5C06CDN\u4E0B\u6C89\u5230\u5730\u5E02\u7EA7\uFF0C\u4EE5\u6B64\u51CF\u8F7B\u538B\u529B\uFF0C\u540C\u65F6\u53EF\u4EE5\u63D0\u5347\u7528\u6237\u4F53\u9A8C\u3002\u8BB2\u5230\u8FD9\u91CC\uFF0C\u5E7F\u5927\u901A\u4FE1\u6C6A\u4EEC\u662F\u4E0D\u662F\u60F3\u5230\u4E86\u4EC0\u4E48\uFF1F\u6CA1\u9519\uFF0C\u8FD9\u4E2A\u548C\u79FB\u52A8\u8FB9\u7F18\u8BA1\u7B97\uFF0C\u6709\u5F02\u66F2\u540C\u5DE5\u4E4B\u5999\u3002</p><video width="100%" height="auto" autoplay="autoplay" controls="controls" loop="loop"><source src="https://vdn3.vzuu.com/SD/93d41dac-2336-11eb-83b0-72776daa6fab.mp4?disable_local_cache=1&amp;auth_key=1646707026-0-0-c49b80321dfd1e7bff1134a43326323c&amp;f=mp4&amp;bu=pico&amp;expiration=1646707026&amp;v=tx" type="video/mp4"></video><p>\u4E00\u76F4\u4EE5\u6765\uFF0C\u968F\u7740\u7F51\u7EDC\u80FD\u529B\u7684\u4E0D\u65AD\u63D0\u5347\uFF0C\u5185\u5BB9\u8D44\u6E90\u548C\u8BA1\u7B97\u80FD\u529B\u90FD\u5728\u4E0D\u65AD\u201C\u5F80\u4E0A\u8D70\u201D\uFF0C\u8D70\u5230\u4E91\u8BA1\u7B97\u4E2D\u5FC3\u3002\u7531\u4E00\u4E2A\u6838\u5FC3\u4E91\u8BA1\u7B97\u4E2D\u5FC3\uFF0C\u5BF9\u6240\u6709\u7EC8\u7AEF\u8282\u70B9\u63D0\u4F9B\u670D\u52A1\u3002</p><p>\u7ED3\u679C\uFF0C\u4EBA\u4EEC\u56DE\u8FC7\u5934\u6765\u53D1\u73B0\uFF0C\u5BF9\u4E8E\u975E\u5E38\u5927\u7684\u9762\u79EF\u533A\u57DF\uFF0C\u975E\u5E38\u591A\u7684\u7528\u6237\u6570\u91CF\uFF0C\u5C24\u5176\u662F\u56FD\u5BB6\u7EA7\u6216\u4E16\u754C\u7EA7\u7684\u670D\u52A1\uFF0C\u4E0D\u7BA1\u4F60\u628A\u8FD9\u4E2A\u4E2D\u5FC3\u8BBE\u5728\u54EA\u91CC\uFF0C\u4E5F\u4E0D\u7BA1\u4F60\u8FD9\u4E2A\u4E2D\u5FC3\u7684\u80FD\u529B\u6709\u591A\u5F3A\u5927\uFF0C\u90FD\u65E0\u6CD5\u514B\u670D<strong>\u7269\u7406\u8DDD\u79BB\u4E0A\u7684\u969C\u788D</strong>\uFF0C\u4F1A\u5BFC\u81F4\u65E0\u6CD5\u5FCD\u53D7\u7684<strong>\u5EF6\u65F6</strong>\u548C<strong>\u7F51\u7EDC\u62E5\u585E</strong>\u3002</p><p>\u4E8E\u662F\u4E4E\uFF0C\u4EBA\u4EEC\u5C31\u5F00\u59CB\u628A\u4E91\u8BA1\u7B97\u4E2D\u5FC3\u8FDB\u884C\u90E8\u5206\u201C\u4E0B\u6C89\u201D\uFF0C\u8FD9\u624D\u6709\u4E86\u96FE\u8BA1\u7B97\u3001\u973E\u8BA1\u7B97\u3002\u751A\u81F3\u4EBA\u4EEC\u5F00\u59CB\u8D28\u7591\uFF0C<strong>\u96C6\u4E2D\u5F0F\u8BA1\u7B97\u662F\u5426\u4F1A\u6700\u7EC8\u88AB\u5206\u5E03\u5F0F\u8BA1\u7B97\u6240\u53D6\u4EE3\uFF1F</strong></p><p>\u4E0D\u540C\u7684\u573A\u666F\u5E26\u6765\u4E0D\u540C\u7684\u9700\u6C42\uFF0C\u4E0D\u540C\u7684\u9700\u6C42\u9700\u8981\u4E0D\u540C\u7684\u7F51\u7EDC\u67B6\u6784\u3002\u573A\u666F\u7684\u591A\u6837\u5316\u662F\u73B0\u5B9E\u5B58\u5728\u7684\uFF0C\u6240\u4EE5\uFF0C\u7F51\u7EDC\u67B6\u6784\u7684\u7075\u6D3B\u5316\uFF0C\u4E5F\u662F\u5FC5\u7136\u7684\u9009\u62E9\u3002</p><p>\u5373\u5C06\u5230\u6765\u76845G\uFF0C\u63D0\u51FA\u4E09\u5927\u573A\u666F\u548C\u5207\u7247\uFF0C\u7528\u540C\u4E00\u5F20\u7F51\u7EDC\uFF0C\u6EE1\u8DB3\u4E0D\u540C\u7684\u9700\u6C42\uFF0C\u5C31\u4F53\u73B0\u4E86\u8FD9\u6837\u7684\u8BBE\u8BA1\u601D\u60F3\uFF0C\u987A\u5E94\u4E86\u6F6E\u6D41\u7684\u53D1\u5C55\u65B9\u5411\u3002</p>',17);function t(o,r){return e}var c=p(i,[["render",t]]);export{c as default};
